#!/usr/bin/env bash
set -Eeuo pipefail

# Backhaul Premium One-Command Installer v3.0.0
# Unique single-file installer: upload only this file as oneclick-v3.sh

GITHUB_REPO="V2grop/backhaul-oneclick"
BRANCH="main"
RAW_BASE="https://raw.githubusercontent.com/${GITHUB_REPO}/${BRANCH}"
CORE_SHA256="a57a8e0c4216e7971718104b5c9744a056d110411179fff789933caff0c53428"
BASE_DIR="/root/backhaul-core"
CORE_PATH="${BASE_DIR}/backhaul_premium"
MANAGER_PATH="/root/backhaul_manager_v3.sh"

fail() { printf '[ERROR] %s\n' "$*" >&2; exit 1; }
[[ ${EUID:-$(id -u)} -eq 0 ]] || fail "با root اجرا کن: sudo -i"

for cmd in curl sha256sum base64; do
  command -v "$cmd" >/dev/null 2>&1 || {
    apt-get update -y >/dev/null
    apt-get install -y curl ca-certificates coreutils >/dev/null
    break
  }
done

mkdir -p "$BASE_DIR"
need_core=true
if [[ -f "$CORE_PATH" ]]; then
  current_sha="$(sha256sum "$CORE_PATH" | awk '{print $1}')"
  [[ "$current_sha" == "$CORE_SHA256" ]] && need_core=false
fi

if [[ "$need_core" == true ]]; then
  printf '[1/3] Downloading Backhaul core...\n'
  tmp_core="$(mktemp)"
  curl -fL --retry 3 --connect-timeout 15 \
    -o "$tmp_core" "${RAW_BASE}/backhaul_premium?cb=$(date +%s)"
  echo "${CORE_SHA256}  $tmp_core" | sha256sum -c - >/dev/null || fail "هش هسته اشتباه است."
  install -o root -g root -m 700 "$tmp_core" "$CORE_PATH"
  rm -f "$tmp_core"
else
  printf '[1/3] Existing core verified; download skipped.\n'
  chmod 700 "$CORE_PATH"
fi

printf '[2/3] Installing full v3 manager...\n'
base64 -d > "$MANAGER_PATH" <<'BACKHAUL_MANAGER_V3_BASE64'

BACKHAUL_MANAGER_V3_BASE64
chmod 700 "$MANAGER_PATH"

bash -n "$MANAGER_PATH" || fail "بررسی نحوی مدیر ناموفق بود."
printf '[3/3] Ready: Backhaul Manager v3.0.0\n\n'
exec bash "$MANAGER_PATH" "$@"
